import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))

def pkg_map(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

bm, am = pkg_map(b), pkg_map(a)
diffs = [(k, bm[k], am.get(k, 'MISSING')) for k in bm if bm[k] != am.get(k)]
diffs += [(k, 'MISSING', am[k]) for k in am if k not in bm]
if diffs:
    for d in diffs: print(f'DIFF: {d}')
else:
    print('All packages resolve identically to baseline.')
"

